import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new Vex({ apiKey: 'vex-key' });

async function generateLesson(plan: string) {
  const msg = await anthropic.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1000,
    tools: [{ type: 'function', name: 'fetch_curriculum', input_schema: {} }],
    messages: [{ role: 'user', content: `Create accessible lesson: ${plan}` }]
  });

  const verified = await vex.verify({
    input: msg.content[0].text,
    policy: 'section-508-accessibility',
    metadata: { audience: 'k-12' }
  });

  return verified.approved ? verified.output : 'Content failed accessibility check';
}
